module top_module(
  input clk,
  input reset,
  output reg [3:0] count
);reg [3:0] obf_next_count;

  always @(posedge clk) begin
    if (reset) begin
      obf_next_count <= 4'b0000;
    end
    else begin
      obf_next_count <= count + 1;
    end
  end

  assign count = obf_next_count;

endmodule
